import{_ as s,o as a,c as e,e as t,f as n}from"./app-19f36e20.js";const i="/godot/images/signal.drawio.svg",c={},o=n('<h1 id="如何在节点之间进行通信" tabindex="-1"><a class="header-anchor" href="#如何在节点之间进行通信" aria-hidden="true">#</a> 如何在节点之间进行通信？</h1><h4 id="什么是信号" tabindex="-1"><a class="header-anchor" href="#什么是信号" aria-hidden="true">#</a> 什么是信号？</h4><p>在 Godot 中，<code>信号(Signal)</code>是一种用于在不同节点对象之间进行通信的机制(如下图所示)。这种机制使得对象之间的交互更加灵活和解耦。</p><p><img src="'+i+'" alt="信号机制"></p><h4 id="如何连接-godot-的内置信号" tabindex="-1"><a class="header-anchor" href="#如何连接-godot-的内置信号" aria-hidden="true">#</a> 如何连接 Godot 的内置信号？</h4><p>在 Godot 中，连接信号的方式有以下两种：</p><ul><li>第一种方式，就是在节点面板中，点击信号的连接按钮。如下图：</li></ul>',7),l=n(`<ul><li>第二种方式，就是直接在代码中，使用 connect 函数来连接：</li></ul><div class="language-gdscript line-numbers-mode" data-ext="gdscript"><pre class="language-gdscript"><code><span class="token keyword">extends</span> <span class="token class-name">Node2D</span>

<span class="token keyword">func</span> <span class="token function">_on_Button_pressed</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token function">print</span><span class="token punctuation">(</span><span class="token string">&quot;按钮被点击了&quot;</span><span class="token punctuation">)</span>

<span class="token keyword">func</span> <span class="token function">_ready</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token variable">$Button</span><span class="token punctuation">.</span><span class="token function">connect</span><span class="token punctuation">(</span><span class="token string">&quot;pressed&quot;</span><span class="token punctuation">,</span> _on_Button_pressed<span class="token punctuation">)</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="如何自定义信号" tabindex="-1"><a class="header-anchor" href="#如何自定义信号" aria-hidden="true">#</a> 如何自定义信号？</h4><div class="custom-container danger"><p class="custom-container-title">自定义信号的关键 3 点:</p><ol><li>signal 关键字定义信号</li><li>emit_signal 函数发送信号</li><li>connect() 函数监听自定义信号</li></ol></div><p>在 Godot 中，您可以通过创建自定义信号来扩展节点的功能。自定义信号允许节点在特定事件发生时发出信号，以便其他节点可以监听并做出响应。</p><p>要自定义信号，请按照以下步骤进行操作：</p><ol><li>在 player 脚本中，使用 <code>signal</code> 关键字定义信号，创建一个名为 <code>destroyed</code> 的自定义信号。例如：</li></ol><div class="language-gdscript line-numbers-mode" data-ext="gdscript"><pre class="language-gdscript"><code><span class="token comment"># player.gd</span>

<span class="token keyword">signal</span> destroyed
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>在玩家死亡的时候，使用 <code>emit_signal</code> 函数发出信号。例如：</li></ol><div class="language-gdscript line-numbers-mode" data-ext="gdscript"><pre class="language-gdscript"><code><span class="token comment"># player.gd</span>

<span class="token comment"># 发出玩家被摧毁信号</span>
<span class="token function">emit_signal</span><span class="token punctuation">(</span><span class="token string">&quot;destroyed&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>在其他节点中，使用 <code>Signal.connect()</code> 函数连接到自定义信号，并定义对应的处理方法。例如：</li></ol><div class="language-gdscript line-numbers-mode" data-ext="gdscript"><pre class="language-gdscript"><code><span class="token comment"># main.gd</span>

<span class="token keyword">func</span> <span class="token function">_ready</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token variable">$player</span><span class="token punctuation">.</span>destroyed<span class="token punctuation">.</span><span class="token function">connect</span><span class="token punctuation">(</span>player_destroyed_callback<span class="token punctuation">)</span> <span class="token comment"># 监听飞船被摧毁的信号</span>

<span class="token keyword">func</span> <span class="token function">player_destroyed_callback</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token function">print</span><span class="token punctuation">(</span><span class="token string">&quot;玩家死亡了&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过自定义信号，节点可以在特定事件发生时与其他节点进行通信，以实现更灵活和可扩展的功能。</p>`,13);function p(d,u){return a(),e("div",null,[o,t(" ![添加信号](/images/add_signal.png) "),l])}const v=s(c,[["render",p],["__file","signal.html.vue"]]);export{v as default};
